1	/**
2	 * OKKI 一键同步脚本
3	 *
4	 * 自动检测浏览器状态 → 登录 → 导航TM → 提取会话元数据 → 增量拉消息
5	 *
6	 * 用法：node scripts/sync_okki.js
7	 *
8	 * 适用所有场景：
9	 * - 刚开机/Chrome没开/没登录 → 自动启动Chrome → 等你登录 → 继续
10	 * - Chrome开着+已登录+在TM页 → 直接抓取
11	 * - Chrome开着但不在TM页 → 自动导航
12	 */
13	
14	const { chromium } = require('playwright');
15	const fs = require('fs');
16	const path = require('path');
17	const http = require('http');
18	
19	const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
20	const DATA_DIR = path.join(__dirname, '..', 'data');
21	const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
22	const CDP_URL = 'http://localhost:9222';
23	const MSG_COUNT = 50;
24	const MAX_PAGES = 20;
25	
26	// ===================== 工具函数 =====================
27	
28	function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
29	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
30	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
31	
32	function sanitizeFilename(cid) {
33	  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
34	}
35	
36	// ===================== CDP 端口检测 =====================
37	
38	function checkCdpPort() {
39	  return new Promise((resolve) => {
40	    const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
41	      let data = '';
42	      res.on('data', c => data += c);
43	      res.on('end', () => {
44	        try {
45	          const json = JSON.parse(data);
46	          resolve(!!json.webSocketDebuggerUrl);
47	        } catch (e) { resolve(false); }
48	      });
49	    });
50	    req.on('error', () => resolve(false));
51	    req.setTimeout(2000, () => { req.destroy(); resolve(false); });
52	  });
53	}
54	
55	// ===================== 主流程 =====================
56	
57	async function main() {
58	  let browser;
59	  let page;
60	  let useCdp = false;
61	
62	  // ---- Step 1: 启动/连接浏览器 ----
63	  const cdpAvailable = await checkCdpPort();
64	  if (cdpAvailable) {
65	    log('检测到 CDP 端口，尝试连接已有 Chrome...');
66	    try {
67	      browser = await chromium.connectOverCDP(CDP_URL);
68	      const pages = browser.contexts()[0]?.pages() || [];
69	      page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
70	      if (!page) {
71	        page = await browser.contexts()[0].newPage();
72	      }
73	      useCdp = true;
74	      log(`CDP 已连接。当前页面: ${page.url()}`);
75	    } catch (e) {
76	      log(`CDP 连接失败: ${e.message}，改用独立启动模式`);
77	    }
78	  }
79	
80	  if (!browser) {
81	    log('启动 Chrome (Profile 4)...');
82	    browser = await chromium.launchPersistentContext(PROFILE, {
83	      channel: 'chrome',
84	      headless: false,
85	      viewport: { width: 1440, height: 900 },
86	    });
87	    page = await browser.newPage();
88	    log('Chrome 已启动');
89	  }
90	
91	  // ---- Step 2: 导航到 OKKI + 登录检测 ----
92	  const currentUrl = page.url();
93	  if (!currentUrl.includes('xiaoman') && !currentUrl.includes('onetalk') && !currentUrl.includes('alibaba')) {
94	    log('导航到 crm.xiaoman.cn...');
95	    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
96	  }
97	
98	  // 检测登录状态
99	  let loginUrl = page.url();
100	  if (loginUrl.includes('login.xiaoman.cn') || loginUrl.includes('login.alibaba.com')) {
101	    log('');
102	    log('========================================');
103	    log('  请在浏览器中登录 OKKI (小满)');
104	    log('  登录后脚本自动继续...');
105	    log('========================================');
106	    log('');
107	
108	    const startTime = Date.now();
109	    const maxWait = 5 * 60 * 1000;
110	    while (Date.now() - startTime < maxWait) {
111	      const url = page.url();
112	      if (!url.includes('login.xiaoman.cn') && !url.includes('login.alibaba.com') && url.includes('crm.xiaoman.cn')) {
113	        log('登录成功！');
114	        break;
115	      }
116	      await sleep(2000);
117	    }
118	    if (page.url().includes('login')) {
119	      log('超时：未检测到登录。退出。');
120	      await browser.close();
121	      process.exit(1);
122	    }
123	  } else {
124	    log('已登录状态');
125	  }
126	
127	  // ---- Step 3: 导航到 TM 消息页面 ----
128	  log('导航到 TM 消息页...');
129	  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
130	  await sleep(3000);
131	
132	  // 可能需要点击侧边栏进入 TM（OKKI 的 /im/ 可能只显示外壳，onetalk 在 iframe 里）
133	  log(`当前 URL: ${page.url()}`);
134	
135	  // ---- Step 4: 等待 onetalk iframe + 数据就绪 ----
136	  log('等待 onetalk iframe 加载...');
137	
138	  // 递归查找 onetalk 页面（可能在嵌套 iframe 中）
139	  function findOnetalkFrame(pageOrFrame) {
140	    const frames = pageOrFrame.frames ? pageOrFrame.frames() : (pageOrFrame.childFrames ? pageOrFrame.childFrames() : []);
141	    for (const f of frames) {
142	      const url = f.url();
143	      // 真正的 onetalk PWA 页面，不是 OKKI 外壳
144	      if (url.startsWith('https://onetalk.alibaba.com/')) return f;
145	      // 递归查找
146	      const found = findOnetalkFrame(f);
147	      if (found) return found;
148	    }
149	    return null;
150	  }
151	
152	  let iframePage = null;
153	  for (let attempt = 0; attempt < 30; attempt++) {
154	    iframePage = findOnetalkFrame(page);
155	    if (iframePage) {
156	      log(`onetalk iframe 已找到 (尝试 ${attempt + 1}): ${iframePage.url().slice(0, 100)}`);
157	      break;
158	    }
159	    if (attempt === 0) {
160	      const bodyText = await page.evaluate(() => document.body.innerText?.slice(0, 500)).catch(() => '');
161	      log(`  页面预览: ${bodyText.slice(0, 200)}`);
162	      // 检查是否在 OKKI 外壳中
163	      const allFrames = page.frames();
164	      log(`  当前 ${allFrames.length} 个 frame:`);
165	      for (const f of allFrames) {
166	        log(`    ${f.url().slice(0, 120)}`);
167	      }
168	    }
169	    await sleep(2000);
170	  }
171	
172	  if (!iframePage) {
173	    log('iframe 未找到。请确认：');
174	    log('  1. 已退出手机阿里卖家');
175	    log('  2. OKKI TM 面板不是 "Click to retry" 状态');
176	    log('  3. TM 面板中能看到会话列表');
177	    log('');
178	    log('脚本保持运行。完成上述操作后回车继续...');
179	    await new Promise(() => {});
180	  }
181	
182	  // ---- Step 5: 提取会话列表（带重试） ----
183	  log('提取会话元数据...');
184	  let convData = null;
185	  for (let attempt = 0; attempt < 20; attempt++) {
186	    convData = await iframePage.evaluate(() => {
187	      const convs = window.__conversationListFullData__;
188	      if (!convs || !Array.isArray(convs)) return { error: 'no __conversationListFullData__', type: typeof convs, count: 0 };
189	      return {
190	        count: convs.length,
191	        list: convs.map(c => ({
192	          cid: c.cid,
193	          name: c.name,
194	          loginId: c.loginId,
195	          aliId: c.aliId,
196	          accountId: c.accountId,
197	          companyName: c.companyName,
198	          country: c.country,
199	          level: c.level,
200	          serviceType: c.serviceType,
201	          conversationType: c.conversationType,
202	          unreadCount: c.unreadCount,
203	          stayTop: c.stayTop,
204	          lastContactTime: c.lastContactTime,
205	          lastContactTimeLong: c.lastContactTimeLong,
206	          createAt: c.createAt,
207	          tagInfo: c.tagInfo,
208	          available: c.available,
209	          complianceCountryCode: c.complianceCountryCode,
210	          latestMessage: c.latestMessage ? {
211	            content: c.latestMessage.content,
212	            messageType: c.latestMessage.messageType,
213	            messageId: c.latestMessage.messageId,
214	            gmtChat: c.latestMessage.gmtChat,
215	            contactRead: c.latestMessage.contactRead,
216	          } : null,
217	        })),
218	      };
219	    }).catch(e => ({ error: e.message, count: 0 }));
220	
221	    if (!convData.error && convData.count > 0) {
222	      log(`提取成功: ${convData.count} 个会话 (尝试 ${attempt + 1})`);
223	      break;
224	    }
225	    if (attempt === 0) {
226	      log(`  等待 TM 数据加载 (${convData.error || '空数据'})...`);
227	    }
228	    await sleep(2000);
229	  }
230	
231	  if (!convData || convData.error || convData.count === 0) {
232	    log(`提取失败: ${convData?.error || '无数据'}`);
233	    log('TM 面板可能未正常加载。请确认能看到会话列表后重新运行脚本。');
234	    await browser.close();
235	    process.exit(1);
236	  }
237	
238	  // 展平结果
239	  const convList = convData.list;
240	  const totalCount = convData.count;
241	
242	  log(`提取到 ${totalCount} 个会话`);
243	
244	  // ---- Step 6: 保存最新元数据 ----
245	  const latestMeta = {
246	    exportedAt: new Date().toISOString(),
247	    total: totalCount,
248	    conversations: convList,
249	  };
250	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
251	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
252	  log(`元数据已保存: tm_conversations_latest.json (${totalCount} 会话)`);
253	
254	  // ---- Step 7: Diff 找出变化的会话 ----
255	  log('对比上次数据...');
256	  let oldMeta = null;
257	  const oldPath = path.join(DATA_DIR, 'tm_conversations_full.json');
258	  if (fs.existsSync(oldPath)) {
259	    oldMeta = JSON.parse(fs.readFileSync(oldPath, 'utf-8'));
260	  }
261	
262	  const changed = [];
263	  const oldMap = new Map();
264	  if (oldMeta?.conversations) {
265	    for (const c of oldMeta.conversations) {
266	      oldMap.set(c.cid, c);
267	    }
268	  }
269	
270	  for (const c of convList) {
271	    const old = oldMap.get(c.cid);
272	    if (!old) {
273	      // 新会话
274	      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
275	      continue;
276	    }
277	    const oldLmId = old.latestMessage?.messageId;
278	    const newLmId = c.latestMessage?.messageId;
279	    const oldLct = old.lastContactTime || 0;
280	    const newLct = c.lastContactTime || 0;
281	
282	    if (oldLmId !== newLmId || newLct > oldLct) {
283	      const reason = oldLmId !== newLmId ? '消息更新' : '时间更新';
284	      changed.push({ cid: c.cid, name: c.name, reason, oldLmId, newLmId });
285	    }
286	  }
287	
288	  log(`变化会话: ${changed.length} 个`);
289	  if (changed.length > 0) {
290	    for (const ch of changed.slice(0, 15)) {
