44	function detectSignals(content) {
45	  const signals = [];
46	  const lower = (content || '').toLowerCase();
47	
48	  // Price/quote signals
49	  if (lower.match(/price|报价|quote|سعر|prix|precio|preço|стоимость|السعر/)) signals.push('PRICE');
50	  if (lower.match(/\$\d+|\d+\s*usd|\d+\s*dollar/)) signals.push('SPECIFIC_PRICE');
51	
52	  // Order signals
53	  if (lower.match(/order|make order|place order|下单|заказ|pedido|commande/)) signals.push('ORDER');
54	  if (lower.match(/pi\b|proforma invoice|proforma|发票/)) signals.push('PI');
55	
56	  // Address/delivery
57	  if (lower.match(/address|delivery|ship|freight|shipping|物流|地址|livraison|envío|الشحن|عنوان/)) signals.push('SHIPPING');
58	  if (lower.match(/dap|ddp|fob|exw|cif|door to door/)) signals.push('INCOTERMS');
59	
60	  // Payment
61	  if (lower.match(/payment|paid|deposit|预付|定金|проплата|depósito|acompte/)) signals.push('PAYMENT');
62	  if (lower.match(/40%|30%|50%|tt\b|bank transfer|alibaba trade/)) signals.push('PAYMENT_TERMS');
63	
64	  // Product selection
65	  if (lower.match(/style|pattern|design|color|size|material|cotton|款|色|码|面料|talla|taille/)) signals.push('PRODUCT');
66	
67	  // Sample
68	  if (lower.match(/sample|样品|muestra|echantillon|عينة/)) signals.push('SAMPLE');
69	
70	  // Quantity
71	  if (lower.match(/quantity|qty|数量|quantité|cantidad|количество|كمية/)) signals.push('QTY');
72	  if (lower.match(/\d+\s*(pcs|pieces|件|pièces)/)) signals.push('SPECIFIC_QTY');
73	
74	  // Decision maker
75	  if (lower.match(/partner|brother|husband|wife|boss|manager|商量|discuss|consult|partenaire/)) signals.push('DECISION_CHAIN');
76	
77	  // Urgency
78	  if (lower.match(/urgent|asap|尽快|urgente/)) signals.push('URGENT');
79	
80	  return signals;
81	}
