87	function analyzeConversation(cid, name, country, metaInfo) {
88	  const fileName = cid.replace(/#/g, '_').replace(/@/g, '_') + '.json';
89	  const filePath = path.join(chatDir, fileName);
90	
91	  if (!fs.existsSync(filePath)) {
92	    return { name, country, error: 'FILE_NOT_FOUND', msgCount: 0 };
93	  }
94	
95	  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
96	  const messages = data.messages || [];
97	
98	  // Filter out system messages and auto-replies
99	  const realMessages = messages.filter(m => {
100	    const ext = m?.message?.extension?.basicMessageInfo;
101	    if (ext) {
102	      try {
103	        const info = JSON.parse(ext);
104	        if (info.systemMessage === true || info.autoReply === true) return false;
105	      } catch(e) {}
106	    }
107	    const content = m?.message?.content?.text?.content || '';
108	    return !isSystemMsg(content);
109	  });
110	
111	  const selfMsgs = realMessages.filter(m => isSelf(m));
112	  const clientMsgs = realMessages.filter(m => !isSelf(m));
113	
114	  // Timeline
115	  const allTimestamps = realMessages.map(m => m?.message?.createAt || 0).filter(Boolean);
116	  const firstContact = allTimestamps.length > 0 ? toDaysAgo(Math.min(...allTimestamps)) : null;
117	  const lastContact = allTimestamps.length > 0 ? toDaysAgo(Math.max(...allTimestamps)) : null;
118	  const lastSelfTs = selfMsgs.length > 0 ? Math.max(...selfMsgs.map(m => m?.message?.createAt || 0)) : null;
119	  const lastClientTs = clientMsgs.length > 0 ? Math.max(...clientMsgs.map(m => m?.message?.createAt || 0)) : null;
120	
121	  // Last non-system, non-emoji message
122	  let lastEffectiveMsg = null;
123	  for (let i = realMessages.length - 1; i >= 0; i--) {
124	    const m = realMessages[i];
125	    const content = m?.message?.content?.text?.content || '';
126	    if (!isEmojiOnly(content)) {
127	      lastEffectiveMsg = {
128	        content: content.substring(0, 200),
129	        isSelf: isSelf(m),
130	        daysAgo: toDaysAgo(m?.message?.createAt || 0),
131	        ts: m?.message?.createAt || 0,
132	      };
133	      break;
134	    }
135	  }
136	
137	  // Client's last message
138	  let lastClientMsg = null;
139	  for (let i = realMessages.length - 1; i >= 0; i--) {
140	    const m = realMessages[i];
141	    if (!isSelf(m)) {
142	      lastClientMsg = {
143	        content: (m?.message?.content?.text?.content || '').substring(0, 200),
144	        daysAgo: toDaysAgo(m?.message?.createAt || 0),
145	      };
146	      break;
147	    }
148	  }
149	
150	  // Aggregate all signals from all messages
151	  const allSignals = new Set();
152	  const recentMsgs = realMessages.slice(-20); // Last 20 messages
153	  recentMsgs.forEach(m => {
154	    const content = m?.message?.content?.text?.content || '';
155	    detectSignals(content).forEach(s => allSignals.add(s));
156	  });
157	
158	  // Determine conversation stage
159	  let stage = 'UNKNOWN';
160	  const signalArr = Array.from(allSignals);
161	  if (signalArr.includes('PI') || (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('SHIPPING'))) {
162	    stage = 'PI_SENT_WAITING_PAYMENT';
163	  } else if (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('PRODUCT')) {
164	    stage = 'NEGOTIATING';
165	  } else if (signalArr.includes('PRICE') || signalArr.includes('SPECIFIC_PRICE')) {
166	    stage = 'QUOTE_SENT';
167	  } else if (signalArr.includes('PRODUCT') && realMessages.length >= 5) {
168	    stage = 'PRODUCT_DISCUSSION';
169	  } else if (realMessages.length >= 3) {
170	    stage = 'INITIAL_INQUIRY';
171	  } else {
172	    stage = 'LOW_ENGAGEMENT';
173	  }
174	
175	  // Priority reassessment
176	  let revisedPriority = null;
177	  if (signalArr.includes('PI') && lastContact <= 3) revisedPriority = 0;
178	  if (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('QTY') && lastContact <= 2) revisedPriority = 0;
179	  if (clientMsgs.length >= 5 && lastContact <= 2) revisedPriority = Math.min(revisedPriority || 9, 0);
180	
181	  // Client reply in last 24h
182	  if (lastClientTs && toDaysAgo(lastClientTs) <= 1) revisedPriority = Math.min(revisedPriority || 9, 0);
183	
184	  return {
185	    name,
186	    country,
187	    totalMsgs: messages.length,
188	    realMsgs: realMessages.length,
189	    selfMsgs: selfMsgs.length,
190	    clientMsgs: clientMsgs.length,
191	    firstContactDaysAgo: firstContact,
192	    lastContactDaysAgo: lastContact,
193	    lastSelfDaysAgo: lastSelfTs ? toDaysAgo(lastSelfTs) : null,
194	    lastClientDaysAgo: lastClientTs ? toDaysAgo(lastClientTs) : null,
195	    signals: signalArr,
196	    stage,
197	    lastEffectiveMsg,
198	    lastClientMsg,
199	    revisedPriority,
200	    cid,
201	  };
202	}
