9	// System message patterns to filter
10	const sysPatterns = [
11	  '自动接待将不再触发', 'Since you have read the conversation',
12	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
13	  '买家有流失风险', 'Buyer has churn risk',
14	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
15	  '反馈', 'AI给您生成了一条回复建议',
16	  'You have a visitor', 'This buyer has been pre-screened',
17	];
18	
19	function isSystemMsg(content) {
20	  if (!content) return true;
21	  for (const p of sysPatterns) {
22	    if (content.includes(p)) return true;
23	  }
24	  return false;
25	}
26	
27	function classify(conv) {
28	  const lastContact = conv.lastContactTime || 0;
29	  const daysAgo = Math.round((now - lastContact) / DAY);
30	  const isUnread = conv.unreadCount > 0;
31	  const latestContent = conv.latestMessage?.content || '';
32	  const latestType = conv.latestMessage?.messageType || '';
33	  const country = conv.complianceCountryCode || '';
34	  const isSys = isSystemMsg(latestContent);
35	
36	  // Core markets
37	  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
38	  const isCore = coreMarkets.includes(country);
39	
40	  let priority = 4;
41	  let signals = [];
42	
43	  // P0 signals
44	  if (isUnread && latestType === 'received' && daysAgo <= 2) {
45	    priority = 0; signals.push('unread+客户消息+2天内');
46	  }
47	  if (isUnread && daysAgo <= 1) {
48	    priority = Math.min(priority, 0); signals.push('unread+1天内');
49	  }
50	  if (daysAgo <= 1 && latestType === 'received' && !isSys) {
51	    priority = Math.min(priority, 0); signals.push('24h内客户回复');
52	  }
53	
54	  // P1 signals
55	  if (isUnread) {
56	    priority = Math.min(priority, 1); signals.push('unread');
57	  }
58	  if (daysAgo <= 3 && latestType === 'received' && !isSys) {
59	    priority = Math.min(priority, 1); signals.push('3天内客户回复');
60	  }
61	  if (isCore && daysAgo <= 7) {
62	    priority = Math.min(priority, 1); signals.push('核心市场活跃');
63	  }
64	  if (daysAgo <= 1) {
65	    priority = Math.min(priority, 1); signals.push('24h有互动');
66	  }
67	
68	  // P2 signals
69	  if (daysAgo <= 7 && !isSys) {
70	    priority = Math.min(priority, 2); signals.push('7天内有互动');
71	  }
72	  if (daysAgo <= 14 && isCore) {
73	    priority = Math.min(priority, 2); signals.push('核心市场2周内');
74	  }
75	
76	  // P3: older but had interaction
77	  if (daysAgo <= 30 && !isSys) {
78	    priority = Math.min(priority, 3);
79	  }
80	
81	  // Downgrade: system message only + old
82	  if (isSys && daysAgo > 7) priority = Math.max(priority, 4);
83	
84	  return { priority, signals, daysAgo, isUnread, latestType, isSys, country, isCore };
85	}
