1	/**
2	 * 阶段1：规则引擎预分类
3	 * 输入：data/cleaned_*.json（阶段0输出）
4	 * 输出：data/classified_rules_<timestamp>.json
5	 *
6	 * 确定性规则（不依赖 AI）：
7	 * - 纯系统消息 + 无实质对话 → P4
8	 * - 我方发送 + 客户从未回复 + 超30天 → P4
9	 * - 沉默超90天 + 无有效互动 → P3
10	 * - 沉默超30天 + messageCount ≤ 3 → P3
11	 * - 未读消息 + 客户最近发送 → P0/P1（待AI细分）
12	 * - 规则覆盖不了的 → 标记 needAI: true
13	 *
14	 * 规则引擎只做确定判断，不确定的不猜，扔给 AI。
15	 */
16	
17	const fs = require('fs');
18	const path = require('path');
19	
20	const DATA_DIR = path.join(__dirname, '..', 'data');
21	
22	// ====== 优先级定义 ======
23	const PRIORITY = {
24	  P0_PAYMENT: 'P0-付款/售后',
25	  P0_INTENT: 'P0-高意向',
26	  P1: 'P1',
27	  P2: 'P2',
28	  P3: 'P3',
29	  P4: 'P4',
30	};
31	
32	// ====== 升级信号关键词 ======
33	const UPGRADE_SIGNALS = [
34	  { re: /下单|place\s*order|make\s*order|send\s*order|confirm\s*order/i, label: '下单信号' },
35	  { re: /PI|proforma\s*invoice|形式发票|发票.*已发|invoice.*sent/i, label: 'PI相关' },
36	  { re: /付款|payment|deposit|depósito|预付|TT|bank\s*transfer/i, label: '付款相关' },
37	  { re: /样品|sample|muestra|échantillon|عينة/i, label: '样品阶段' },
38	  { re: /地址.*已|address.*confirm|ship.*address|delivery.*address/i, label: '地址确认' },
39	  { re: /partner|合伙|商量|discuss.*partner|conversation.*boss/i, label: '合伙商量' },
40	  { re: /运费|shipping\s*cost|freight|FOB|CIF|DDP|EXW/i, label: '运费讨论' },
41	  { re: /价格|price|pricing|quote|quotation|cotización|precio/i, label: '价格讨论' },
42	  { re: /选.*款|select.*style|choose.*design|pick.*item/i, label: '选款' },
43	  { re: /数量|quantity|pcs|pieces|units|qty/i, label: '数量讨论' },
44	];
45	
46	// ====== 降级信号关键词 ======
47	const DOWNGRADE_SIGNALS = [
48	  { re: /not\s*interested|不感兴趣|no\s*thanks/i, label: '不感兴趣' },
49	  { re: /店铺.*转让|sell.*shop|转让|transfer.*business/i, label: '非采购意图' },
50	];
51	
52	// ====== 工具函数 ======
53	
54	function hasUpgradeSignals(text) {
55	  if (!text || typeof text !== 'string') return [];
56	  return UPGRADE_SIGNALS.filter((s) => s.re.test(text)).map((s) => s.label);
57	}
58	
59	function hasDowngradeSignals(text) {
60	  if (!text || typeof text !== 'string') return [];
61	  return DOWNGRADE_SIGNALS.filter((s) => s.re.test(text)).map((s) => s.label);
62	}
63	
64	function isPureSystemMessages(entry) {
65	  const flags = entry._flags || {};
66	  if (!flags.isLatestSystemMsg) return false;
67	  const msgCount = entry._computedMessageCount || 0;
68	  if (msgCount <= 1) return true;
69	  if (Array.isArray(entry.messages) && entry.messages.every((m) => {
70	    const text = m.text || m.latestMessageContent || '';
71	    return text.trim().length === 0 || /^(自动接待|Marco|AI给您|反馈|Since you have)/.test(text);
72	  })) return true;
73	  return false;
74	}
75	
76	function isValidInteraction(entry) {
77	  const msg = entry.latestMessageContent || '';
78	  if (!msg || msg.trim().length === 0) return false;
79	  if (entry._flags?.isLatestSystemMsg && entry._computedMessageCount <= 1) return false;
80	  if (msg === '[图片]' || msg === '[商品]' || msg === '[表情]') return true;
81	  if (msg.length < 2) return false;
82	  return true;
83	}
84	
85	function customerNeverReplied(entry) {
86	  if (entry._messageDirection) {
87	    const dir = entry._messageDirection;
88	    if (dir.received === 0 && dir.sent > 0) return true;
89	  }
90	  if (entry.latestMessageType === 'send' && !entry.msgFromCustomer) return true;
91	  return false;
92	}
93	
94	// ====== 主分类逻辑 ======
95	
96	function classifyCustomer(entry) {
97	  const silenceDays = entry._silenceDays || 999;
98	  const msgCount = entry._computedMessageCount || 0;
99	  const flags = entry._flags || {};
100	  const issues = entry._issues || [];
101	  const reason = [];
102	  const priority = { level: null, subType: null, confidence: 'deterministic' };
103	
104	  const effectiveMsg = flags.latestMsgReplaced ? (entry._replacedMessageContent || '') : (entry.latestMessageContent || '');
105	  const isUnread = entry.isUnread || entry.unreadCount > 0;
106	  const msgType = entry.latestMessageType;
107	
108	  // Rule 1: 纯系统消息 + 无实质对话 → P4
109	  if (isPureSystemMessages(entry)) {
110	    priority.level = 'P4';
111	    reason.push('纯系统消息，无实质对话');
112	    return { ...priority, reasons: reason, needAI: false };
113	  }
114	
115	  // Rule 2: 我方发送 + 客户从未回复 + 超30天 → P4
116	  if (customerNeverReplied(entry) && silenceDays > 30) {
117	    priority.level = 'P4';
118	    reason.push('我方单向发送，客户从未回复，超30天');
119	    return { ...priority, reasons: reason, needAI: false };
120	  }
121	
122	  // Rule 3: 沉默超90天 + 无有效互动 → P3
123	  if (silenceDays > 90 && !isValidInteraction(entry)) {
124	    priority.level = 'P3';
125	    reason.push('沉默超90天，无有效互动');
126	    return { ...priority, reasons: reason, needAI: false };
127	  }
128	
129	  // Rule 4: 沉默超90天 + 有互动但无近期活跃 → P3
130	  if (silenceDays > 90 && msgCount <= 3) {
131	    priority.level = 'P3';
132	    reason.push('沉默超90天，消息≤3条');
133	    return { ...priority, reasons: reason, needAI: false };
134	  }
135	
136	  // Rule 5: 沉默超30天 + 消息≤3条 + 非未读 → P3
137	  if (silenceDays > 30 && msgCount <= 3 && !isUnread) {
138	    priority.level = 'P3';
139	    reason.push('沉默超30天，消息≤3条，非未读');
140	    return { ...priority, reasons: reason, needAI: false };
141	  }
142	
143	  // Rule 6: 非采购意图 → P4
144	  const downgrade = hasDowngradeSignals(effectiveMsg);
145	  if (downgrade.length > 0 && !isUnread) {
146	    priority.level = 'P4';
147	    reason.push(`降级信号: ${downgrade.join(', ')}`);
148	    return { ...priority, reasons: reason, needAI: false };
149	  }
150	
151	  // Rule 7: 30天内无互动 + 消息数≤10 → P3 (rule-based P3 fallback)
152	  if (silenceDays > 30 && msgCount <= 10 && !isUnread) {
153	    priority.level = 'P3';
154	    reason.push('30天+无互动，消息少');
155	    return { ...priority, reasons: reason, needAI: false };
156	  }
157	
158	  // Rule 8: 30天内无互动 → P2/P3 边界 → needAI
159	  if (silenceDays > 30 && !isUnread) {
160	    priority.level = 'P2';
161	    reason.push('30天内无互动（需AI确认是否降为P3）');
162	    return { ...priority, reasons: reason, needAI: true };
163	  }
164	
165	  // Rule 9: 未读消息 + 客户发送 → P0/P1 (待AI细分)
166	  if (isUnread && msgType === 'received') {
167	    const signals = hasUpgradeSignals(effectiveMsg);
168	    if (signals.some((s) => s.includes('下单') || s.includes('PI') || s.includes('付款') || s.includes('地址确认'))) {
169	      priority.level = 'P0';
170	      priority.subType = '高意向';
171	      reason.push('未读+客户消息+升级信号');
172	      return { ...priority, reasons: reason, needAI: true };
173	    }
174	    priority.level = 'P1';
175	    reason.push('未读消息，客户发送（需AI细分P0/P1）');
176	    return { ...priority, reasons: reason, needAI: true };
177	  }
178	
179	  // Rule 10: 未读消息 + 我方发送 → P1
180	  if (isUnread && msgType === 'send') {
181	    priority.level = 'P1';
182	    reason.push('未读消息，我方发送（需AI确认）');
183	    return { ...priority, reasons: reason, needAI: true };
184	  }
185	
186	  // Rule 11: 有升级信号 + 近期活跃(≤7天) → P0/P1 (待AI细分)
187	  const signals = hasUpgradeSignals(effectiveMsg);
188	  if (signals.length > 0 && silenceDays <= 7) {
189	    if (signals.some((s) => s.includes('下单') || s.includes('PI') || s.includes('付款'))) {
190	      priority.level = 'P0';
191	      priority.subType = '待确认';
192	      reason.push(`强升级信号+7天内活跃: ${signals.slice(0, 3).join(', ')}`);
193	      return { ...priority, reasons: reason, needAI: true };
194	    }
195	    priority.level = 'P1';
196	    reason.push(`升级信号+7天内活跃: ${signals.slice(0, 3).join(', ')}`);
197	    return { ...priority, reasons: reason, needAI: true };
198	  }
199	
200	  // Rule 12: 近期活跃(≤14天) → P2
201	  if (silenceDays <= 14) {
202	    priority.level = 'P2';
203	    reason.push('14天内活跃');
204	    return { ...priority, reasons: reason, needAI: true };
205	  }
206	
207	  // Rule 13: 有互动但在普通范围 → P2, needAI
208	  if (silenceDays <= 30) {
209	    priority.level = 'P2';
210	    reason.push('30天内互动过');
211	    return { ...priority, reasons: reason, needAI: true };
212	  }
213	
214	  // Fallback: needAI
215	  priority.level = 'P2';
216	  reason.push('规则覆盖不全，需AI判断');
217	  return { ...priority, reasons: reason, needAI: true };
218	}
219	
220	// ====== 主处理 ======
221	
222	function processAll(data) {
223	  const customers = data.customers || [];
224	  const classified = customers.map((c) => {
225	    const result = classifyCustomer(c);
226	    return {
227	      ...c,
228	      _rulePriority: result.level,
229	      _ruleSubType: result.subType || null,
230	      _ruleReasons: result.reasons,
231	      _needAI: result.needAI,
232	      _ruleConfidence: result.confidence || 'deterministic',
233	    };
234	  });
235	
236	  const stats = {
237	    total: classified.length,
238	    byPriority: {},
239	    needAI: classified.filter((c) => c._needAI).length,
240	    deterministic: classified.filter((c) => !c._needAI).length,
241	  };
242	
243	  for (const c of classified) {
244	    stats.byPriority[c._rulePriority] = (stats.byPriority[c._rulePriority] || 0) + 1;
245	  }
246	
247	  return {
248	    classifiedAt: new Date().toISOString(),
249	    source: data.processedAt || data.capturedAt || 'unknown',
250	    stats,
251	    customers: classified,
252	  };
253	}
254	
255	// ====== CLI ======
256	
257	function findLatestCleaned() {
258	  const files = fs.readdirSync(DATA_DIR).filter((f) => f.startsWith('cleaned_') && f.endsWith('.json'));
259	  if (files.length === 0) return null;
260	  files.sort().reverse();
261	  return files[0];
262	}
