282	  }
283	
284	  console.log(`读取: ${path.basename(inputFile)}`);
285	  const raw = JSON.parse(fs.readFileSync(inputFile, 'utf-8'));
286	  const result = processAll(raw);
287	
288	  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
289	  const outFile = path.join(DATA_DIR, `classified_rules_${ts}.json`);
290	  fs.writeFileSync(outFile, JSON.stringify(result, null, 2), 'utf-8');
291	
292	  console.log(`输出: ${path.basename(outFile)}`);
293	  console.log(`统计: ${result.stats.total} 个客户`);
